#include <iostream>
#include <string>
#include <algorithm>

class Solution {
public:
    std::string multiply(std::string num1, std::string num2) {
        int carry = 0;
        int len1 = num1.length();
        int len2 = num2.length();

        std::string result;
        result.reserve(len1 + len2);

        for (int i = len1 - 1; i >= 0; i--) {
            int digit1 = std::stoi(std::substr(num1, i, 1));
            int digit2 = std::stoi(std::substr(num2, i, 1));

            int sum = (digit1 * 10 * 10 + digit2) + carry;
            result.push_back(sum % 10);
            carry = sum / 10;
        }

        while (carry > 0) {
            result.push_back(carry % 10);
            carry = carry / 10;
        }

        return result;
    }
};
